  methods: {
    openAPP() {
      var IOSAPP = document.getElementById("appurl").value;

      if (IOSAPP == "") {
        IOSAPP = "sgcchnlbs://order.start?workOrder=10011002";
        this.openOtherApp(IOSAPP);
      } else if (IOSAPP != "") {
        this.openOtherApp(IOSAPP);
      } else {
        alert("请输入正确的值！");
      }
    },
    /**
		打开第三方 百度地图 app 
